starterCss:
/* Refactor using native CSS nesting.
   The result should produce identical styles
   but with nested selectors (fewer top-level rules). */
.main-nav {
  display: flex;
  gap: 4px;
  background-color: #1a1a2e;
  padding: 8px;
  border-radius: 8px;
}
.main-nav .main-nav-link {
  color: #a0a0b8;
  text-decoration: none;
  padding: 8px 16px;
  border-radius: 4px;
  transition: color 0.2s, background-color 0.2s;
}
.main-nav .main-nav-link:hover {
  color: white;
  background-color: rgba(255, 255, 255, 0.1);
}
.main-nav .main-nav-link.active {
  color: white;
  background-color: #007bff;
}

